const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const session = require('express-session');
const bodyParser = require('body-parser');
const bcrypt = require('bcrypt');
const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const users = {}; // In-memory user storage for demonstration
const sessions = {}; // In-memory session storage for demonstration

app.use(bodyParser.json());
app.use(session({
  secret: 'your_secret_key',
  resave: false,
  saveUninitialized: true,
}));

app.post('/register', async (req, res) => {
  const { username, password } = req.body;
  const hashedPassword = await bcrypt.hash(password, 10);
  users[username] = { password: hashedPassword, score: 0 };
  res.status(201).send('User registered');
});

app.post('/login', async (req, res) => {
  const { username, password } = req.body;
  const user = users[username];
  if (user && await bcrypt.compare(password, user.password)) {
    req.session.username = username;
    res.send('Logged in');
  } else {
    res.status(401).send('Invalid credentials');
  }
});

io.use((socket, next) => {
  const sessionId = socket.handshake.headers['session-id'];
  if (sessions[sessionId]) {
    socket.username = sessions[sessionId];
    next();
  } else {
    next(new Error('Authentication error'));
  }
});

io.on('connection', (socket) => {
  console.log(`${socket.username} connected`);

  socket.on('submitScore', (score) => {
    if (typeof score === 'number' && score >= 0) {
      users[socket.username].score += score;
      io.emit('updateLeaderboard', getLeaderboard());
    }
  });

  socket.on('disconnect', () => {
    console.log(`${socket.username} disconnected`);
  });
});

function getLeaderboard() {
  return Object.entries(users)
    .map(([username, data]) => ({ username, score: data.score }))
    .sort((a, b) => b.score - a.score);
}

server.listen(3000, () => {
  console.log('Server is running on port 3000');
});